"""Handler for generate_text_progress - routes by tool_type from SQL."""

import uuid
from typing import Any, cast

from app.infra.v4.websocket.get_db_connection import get_db_connection
from app.infra.v4.websocket.handler_wrapper import handle_internal_event
from app.infra.v4.websocket.openapi_helpers import register_server_endpoint
from app.infra.v4.websocket.typed_emit import emit_to_client, emit_to_internal
from app.main import get_internal_sio
# Import autogenerated types
from app.sql.types import (TextToolProgressUpdateApiRequest,
                           TextToolProgressUpdateSqlParams,
                           TextToolProgressUpdateSqlRow)
from pydantic import BaseModel

# Placeholder for SQL-generated type (will be auto-generated when SQL is executed)
class TextGenerationErrorApiRequest(BaseModel):
    """Placeholder - will be replaced by SQL-generated type."""
    error_message: str
    resource_id: uuid.UUID | None = None
    group_id: uuid.UUID | None = None
from fastapi import APIRouter
from utils.sql_helper import execute_sql_typed

internal_sio = get_internal_sio()
server_router = APIRouter()

SQL_PATH = "app/sql/v4/generate/text/text_tool_progress_update_complete.sql"


async def _generate_text_progress_impl(
    sid: str,
    data: TextToolProgressUpdateApiRequest,
    profile_id: uuid.UUID,
    group_id: uuid.UUID | None = None,
) -> None:
    """Handle progress - SQL accumulates arguments, returns tool_type for routing."""
    if data.progress_type not in ("tool_call_start", "tool_call_progress"):
        return

    try:
        async with get_db_connection() as conn:
            # Call SQL - SQL handles tool lookup, tool_call creation, argument accumulation
            # Get arguments_delta from data
            arguments_delta = (
                getattr(data, "arguments_delta", None)
                or getattr(data, "arguments_raw", "")
                or ""
            )

            # Convert run_id and resource_id to UUID if they're strings
            # ApiRequest types use strings, SqlParams use UUIDs
            run_id_val: uuid.UUID
            if isinstance(data.run_id, uuid.UUID):
                run_id_val = data.run_id
            else:
                run_id_val = uuid.UUID(str(data.run_id))
            
            resource_id_val: uuid.UUID | None = None
            if data.resource_id:
                if isinstance(data.resource_id, uuid.UUID):
                    resource_id_val = data.resource_id
                else:
                    resource_id_val = uuid.UUID(str(data.resource_id))

            params = TextToolProgressUpdateSqlParams(
                run_id=run_id_val,
                tool_call_id=data.tool_call_id,
                call_id=data.call_id,
                tool_name=data.tool_name,
                arguments_delta=arguments_delta,  # Delta - SQL accumulates
                progress_type=data.progress_type,
                resource_id=resource_id_val,
            )

            result = cast(
                TextToolProgressUpdateSqlRow,
                await execute_sql_typed(conn, SQL_PATH, params=params),
            )

            # SQL returns tool_type (stable enum) - use this for routing!
            tool_type = result.tool_type  # e.g., "title", "html", "schema"

            # Emit progress to client
            from app.main import sio as client_sio
            await client_sio.emit(
                "text_generation_progress",
                {
                    "success": True,
                    "type": data.progress_type,
                    "resource_id": str(data.resource_id) if data.resource_id else None,
                    "run_id": str(data.run_id),
                    "tool_call_id": result.tool_call_id,
                    "call_id": result.persisted_call_id,
                    "tool_id": str(result.tool_id),
                    "tool_type": tool_type,  # Pass tool_type (stable enum)
                    "tool_name": result.tool_name,  # For reference only
                    "arguments_raw": result.arguments_raw,  # Accumulated by SQL
                },
                room=sid,
            )

    except RuntimeError:
        await emit_to_internal(
            "generate_text_error",
            TextGenerationErrorApiRequest(
                error_message="Database connection unavailable",
                resource_id=data.resource_id if hasattr(data, 'resource_id') else None,
                group_id=str(group_id) if group_id else None,
            ),
            sid=sid,
        )
    except Exception as e:
        await emit_to_internal(
            "generate_text_error",
            TextGenerationErrorApiRequest(
                error_message=f"Progress update failed: {str(e)}",
                resource_id=data.resource_id if hasattr(data, 'resource_id') else None,
                group_id=str(group_id) if group_id else None,
            ),
            sid=sid,
        )


@internal_sio.on("generate_text_progress")  # type: ignore
async def generate_text_progress_internal(
    data: dict[str, Any],
) -> None:
    """Handle generate_text_progress event from internal bus."""
    await handle_internal_event(
        data=data,
        request_type=TextToolProgressUpdateApiRequest,
        handler=_generate_text_progress_impl,  # type: ignore[arg-type]
        error_event_name="generate_text_error",
        error_response_type=None,  # Will be auto-generated from error SQL if needed
    )


register_server_endpoint(
    server_router,
    "/generate_text_progress",
    TextToolProgressUpdateApiRequest,
    "Handle text generation tool progress updates",
)

